const matches = $input.all();
const monthlyVolume = {};
for (const match of matches) {
  const data = match.json;
  const date = new Date(data.played_at || Date.now());
  const key = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
  monthlyVolume[key] = (monthlyVolume[key] || 0) + 1;
}
const series = Object.entries(monthlyVolume)
  .sort(([a], [b]) => a.localeCompare(b))
  .map(([month, count]) => ({ month, count }));
const lastCount = series[series.length - 1]?.count || 0;
const prevCount = series[series.length - 2]?.count || lastCount;
const growthRate = prevCount > 0 ? ((lastCount - prevCount) / prevCount * 100).toFixed(1) : 0;
return [{ json: {
  series,
  total_months: series.length,
  latest_month: series[series.length - 1]?.month || 'N/A',
  latest_count: lastCount,
  growth_rate: growthRate + '%',
  peak_month: series.reduce((a, b) => a.count > b.count ? a : b, { month: 'N/A', count: 0 })
}}];

const items = $input.all();
const results = [];
for (const item of items) {
  const d = item.json;
  const forecast = d.forecast || [{ month: 'N/A', predicted: 0 }];
  const trend = parseFloat(d.growth_rate || '0');
  let trendLabel = '';
  if (trend > 15) trendLabel = '🚀 Strong Growth';
  else if (trend > 5) trendLabel = '📈 Moderate Growth';
  else if (trend > -5) trendLabel = '➡️ Stable';
  else trendLabel = '📉 Declining';
  results.push({
    json: {
      analysis_date: new Date().toISOString(),
      current_month: d.latest_month,
      current_volume: d.latest_count,
      growth_rate: d.growth_rate,
      trend_label: trendLabel,
      forecast_next_3_months: forecast,
      peak_month: d.peak_month,
      model: 'ARIMA (MAE=360 matches/month)',
      recommendation: trend < -10 ? '⚠️ Volume declining — investigate scheduling issues' : '✅ Volume on track'
    }
  });
}
return results;

const items = $input.all();
const alert = {
  type: 'VOLUME_DECLINE_ALERT',
  pipeline: 'Time Series — Monthly Forecast',
  timestamp: new Date().toISOString(),
  current_month: items[0]?.json?.current_month,
  current_volume: items[0]?.json?.current_volume,
  growth_rate: items[0]?.json?.growth_rate,
  message: 'Match volume declining — check tournament scheduling',
  email_to: 'mohamedyassine.hammouda@esprit.tn'
};
await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://127.0.0.1:5000/log_error',
  headers: { 'Content-Type': 'application/json' },
  body: alert,
  json: true
});
return [{ json: alert }];

const items = $input.all();
const predictions = items.map(item => ({
  match_id: 'FORECAST_' + (item.json.current_month || 'N/A'),
  predicted_winner: item.json.trend_label || 'Unknown',
  probability_team1: item.json.current_volume || 0,
  probability_team2: parseFloat(item.json.growth_rate) || 0,
  timestamp: item.json.analysis_date || new Date().toISOString()
}));
const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://127.0.0.1:5000/save_predictions',
  headers: { 'Content-Type': 'application/json' },
  body: { predictions },
  json: true
});
return [{ json: { ...response, forecast_saved: true } }];

const items = $input.all();
const report = items[0]?.json || {};
const emailBody = `
🎾 PADEL ML — Weekly Time Series Report
==========================================
Date: ${new Date().toLocaleDateString('fr-FR')}

📊 CURRENT STATUS
- Month: ${report.current_month || 'N/A'}
- Volume: ${report.current_volume || 0} matches
- Growth: ${report.growth_rate || '0%'}
- Trend: ${report.trend_label || 'N/A'}

🔮 FORECAST (next 3 months)
${JSON.stringify(report.forecast_next_3_months || [], null, 2)}

🏆 Peak Month: ${JSON.stringify(report.peak_month || {})}

💡 Recommendation: ${report.recommendation || 'N/A'}

Model: ${report.model || 'ARIMA'}
`;
return [{ json: { email_body: emailBody, email_to: 'mohamedyassine.hammouda@esprit.tn', subject: '🎾 Padel ML Weekly Forecast Report' } }];
